import{_ as t,o as a,c as i,a0 as s}from"./chunks/framework.jwovEGr5.js";const h=JSON.parse('{"title":"Subscription & Grant Tests","description":"","frontmatter":{},"headers":[],"relativePath":"testing/subscription-tests.md","filePath":"testing/subscription-tests.md"}'),r={name:"testing/subscription-tests.md"};function n(l,e,o,c,d,u){return a(),i("div",null,[...e[0]||(e[0]=[s('<h1 id="subscription-grant-tests" tabindex="-1">Subscription &amp; Grant Tests <a class="header-anchor" href="#subscription-grant-tests" aria-label="Permalink to &quot;Subscription &amp; Grant Tests&quot;">​</a></h1><p>Use this guide to confirm the manual subscription flow, grant lifecycle, suspension rules, and quota thresholds.</p><h2 id="test-1-direct-request-cycle" tabindex="-1">Test 1. Direct request cycle <a class="header-anchor" href="#test-1-direct-request-cycle" aria-label="Permalink to &quot;Test 1. Direct request cycle&quot;">​</a></h2><ol><li>Sign in as a role allowed to request premium. Expected result: <strong>Support &amp; Plans</strong> is available.</li><li>Create a new subscription request. Expected result: the request appears as <code>pending</code>.</li><li>Sign in as Supreme Admin and open the request queue. Expected result: the request is visible.</li><li>Send payment instructions. Expected result: the request moves to <code>awaiting_payment</code>.</li><li>Sign back in as the requester and reply in the thread. Expected result: the reply is stored on the request conversation.</li><li>Sign back in as Supreme Admin and complete the request with a plan assignment. Expected result: the request moves to <code>completed</code>.</li><li>Return to the requester scope and inspect the usage panel. Expected result: the plan is active and the premium features tied to it are available.</li></ol><h2 id="test-2-kingdom-grant-lifecycle" tabindex="-1">Test 2. Kingdom grant lifecycle <a class="header-anchor" href="#test-2-kingdom-grant-lifecycle" aria-label="Permalink to &quot;Test 2. Kingdom grant lifecycle&quot;">​</a></h2><ol><li>Sign in as King for a premium kingdom with grant slots. Expected result: the grant manager is available.</li><li>Create a grant offer for an alliance. Expected result: the offer appears as pending.</li><li>Sign in as Alliance Leader for that alliance and accept the grant. Expected result: the alliance plan source changes to an accepted kingdom grant.</li><li>Open analytics as that Alliance Leader. Expected result: any grant-carried analytics features become available, including the Kingdom tab only if the grant includes <code>kingdom_analytics_for_granted_alliances</code>.</li><li>Sign back in as King and revoke the grant. Expected result: the grant ends.</li><li>Return to the alliance account and re-open analytics. Expected result: grant-driven premium access is gone again.</li></ol><h2 id="test-3-suspension-cascade" tabindex="-1">Test 3. Suspension cascade <a class="header-anchor" href="#test-3-suspension-cascade" aria-label="Permalink to &quot;Test 3. Suspension cascade&quot;">​</a></h2><ol><li>Prepare one directly subscribed alliance and one non-direct alliance under the same kingdom. Expected result: both are active before the test starts.</li><li>Suspend the kingdom for <code>usage_limit</code> conditions. Expected result: the non-direct alliance enters limited mode.</li><li>Check the directly subscribed alliance. Expected result: it stays active and usable.</li><li>Check the non-direct alliance. Expected result: it shows limited or suspended behavior with writes blocked.</li></ol><h2 id="test-4-quota-thresholds" tabindex="-1">Test 4. Quota thresholds <a class="header-anchor" href="#test-4-quota-thresholds" aria-label="Permalink to &quot;Test 4. Quota thresholds&quot;">​</a></h2><ol><li>Raise usage of one hard-limited resource to about 80%. Expected result: a warning banner appears.</li><li>Raise the same resource to about 95%. Expected result: a critical warning appears.</li><li>Raise the same resource to 100%. Expected result: creation of that specific resource is blocked.</li><li>Try a new write after the 100% threshold. Expected result: the UI shows a quota-limit block such as <strong>&quot;Quota limits were reached. New writes are blocked until old resources are cleaned up or additional capacity is granted.&quot;</strong></li></ol>',10)])])}const g=t(r,[["render",n]]);export{h as __pageData,g as default};
